public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    private StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: Default renderer changed from Professional to System.
        // Explicitly set to preserve the .NET 8 visual appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }
}

public class MyDropDownEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context) =>
        UITypeEditorEditStyle.DropDown;

    public override object? EditValue(
        ITypeDescriptorContext? context,
        IServiceProvider provider,
        object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService is null) return value;

        using var control = CreateEditControl(value);
        // .NET 9: DropDownControl(null) now throws ArgumentNullException.
        // Guard against null to preserve safe behavior.
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = GetValueFromControl(control);
        }

        return value;
    }

    private static Control? CreateEditControl(object? currentValue) => new ListBox();
    private static object? GetValueFromControl(Control control) => (control as ListBox)?.SelectedItem;
}

